import Foundation

class AnalyticsLogger {
    
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logUserInteraction(event: String, userId: String?) {
        guard let userId = userId else {
            NSLog("User interaction event: \(event)")
            return
        }
        NSLog("User interaction event: \(event), User ID: \(userId)")
    }
    
    func logAuthenticationFlow(email: String, success: Bool) {
        let status = success ? "successful" : "failed"
        NSLog("Authentication \(status) for email: \(email)")
    }
    
    func logAPICall(endpoint: String, requestPayload: [String: Any]?) {
        if let payload = requestPayload {
            print("API Call to \(endpoint) with payload: \(payload)")
        } else {
            print("API Call to \(endpoint) with no payload")
        }
    }
    
    func logAPIResponse(endpoint: String, responsePayload: [String: Any]?, error: Error?) {
        if let error = error {
            NSLog("Error in API Call to \(endpoint): \(error.localizedDescription)")
        } else if let payload = responsePayload {
            print("API Response from \(endpoint): \(payload)")
        } else {
            print("API Response from \(endpoint) with no data")
        }
    }
    
    func logUserDataChange(userId: String, changes: [String: Any]) {
        NSLog("User data changed for User ID: \(userId), Changes: \(changes)")
    }
    
    func logError(condition: String, error: Error) {
        NSLog("Error occurred: \(condition), Error: \(error.localizedDescription)")
    }
}

